import React, { useState } from 'react';
import './App.css';
//import { auth } from './components/firebase_setup';
import { SignInWithGoogle } from './components/authentication';
import { useAuth } from './contexts';
import { Navigate } from 'react-router-dom';

  //using this will allows easier way to check if user is logged in


function Signin() {
  const { userLoggedIn } = useAuth();
  const [isSigningIn, setIsSigningIn] = useState(false);
  const [error, setError] = useState('');

  const onSubmit = async (e) => {
    e.preventDefault();
    setIsSigningIn(true);
    try {
      await SignInWithGoogle();
      setIsSigningIn(false);
    } catch (err) {
      setError('Failed to sign in');
      setIsSigningIn(false);
    }
  }

  return (
    <div className="Signin">
      {userLoggedIn && <Navigate to="/home" replace={true} />}
      <header className="SignIn-Header">
        <h1>Welcome to Catsta!!!</h1>
      </header>
      <section className='button'>
        <button onClick={onSubmit} disabled={isSigningIn}>
          {isSigningIn ? 'Signing in...' : 'Sign in with Google'}
        </button>
        {error && <p style={{ color: 'red' }}>{error}</p>}
      </section>
    </div>
  );
}


function HomePage () {
  return (
    <div className='HomePage'>
      <h1>This is a placeholder for catsa HomePage</h1>
    </div>
  );
}

//line {user ? <frontpage /> : <SignIn />} is basically like if the user is logged in show frontpage, if not show signIn
function App() {
  const { userLoggedIn } = useAuth();
  return (
    <div className="App">
      {userLoggedIn ? <HomePage /> : <Signin />}
    </div>
  );
}


export default App;
